package co.edu.elecciones.controller; import co.edu.elecciones.commons.dto.ApiResponse; import co.edu.elecciones.domain.*; import co.edu.elecciones.dto.Requests; import co.edu.elecciones.repository.*; import co.edu.elecciones.service.AuditService; import jakarta.servlet.http.HttpServletRequest; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/partidos") public class PartidosController { private final PartyRepository repo; private final AuditService audit;  public PartidosController(PartyRepository repo, AuditService audit){this.repo=repo;this.audit=audit;}
 @GetMapping public ApiResponse<List<Party>> all(){return ApiResponse.ok("OK",repo.findAll());}
 @GetMapping("/{id}") public ApiResponse<Party> one(@PathVariable Long id){return ApiResponse.ok("OK",repo.findById(id).orElseThrow());}
 @PostMapping public ApiResponse<Party> create(@RequestBody Requests.PartyRequest req, HttpServletRequest http){ Party u=new Party(); u.name=req.name(); u.acronym=req.acronym(); u.color=req.color(); u.foundationYear=req.foundationYear(); if(req.active()!=null) u.active=req.active(); var saved=repo.save(u); audit.log("CREATE","Party",saved.id,"Creación",http); return ApiResponse.ok("Creado",saved);}
 @PutMapping("/{id}") public ApiResponse<Party> update(@PathVariable Long id,@RequestBody Requests.PartyRequest req,HttpServletRequest http){ var u=repo.findById(id).orElseThrow(); u.name=req.name(); u.acronym=req.acronym(); u.color=req.color(); u.foundationYear=req.foundationYear(); if(req.active()!=null) u.active=req.active(); var saved=repo.save(u); audit.log("UPDATE","Party",saved.id,"Actualización",http); return ApiResponse.ok("Actualizado",saved);}
 @DeleteMapping("/{id}") public ApiResponse<Void> delete(@PathVariable Long id,HttpServletRequest http){repo.deleteById(id); audit.log("DELETE","Party",id,"Eliminación",http); return ApiResponse.ok("Eliminado",null);}
}
